// AUTO-GENERATED (do not edit by hand). Halftone world-map dots for the
// investor-network section, sampled from Natural Earth 110m land on an
// equirectangular grid. See FAV-17. viewBox is 1000x374.
export const MAP_VIEWBOX = { w: 1000, h: 374 } as const;

/** Equirectangular window used to project lon/lat -> viewBox units. */
export const MAP_PROJ = {"LON_MIN":-168,"LON_MAX":190,"LAT_MIN":-56,"LAT_MAX":78} as const;

/** Project a [lon, lat] pair into the map viewBox. */
export function project(lon: number, lat: number): [number, number] {
  const { LON_MIN, LON_MAX, LAT_MAX, LAT_MIN } = MAP_PROJ;
  const x = ((lon - LON_MIN) / (LON_MAX - LON_MIN)) * MAP_VIEWBOX.w;
  const y = ((LAT_MAX - lat) / (LAT_MAX - LAT_MIN)) * MAP_VIEWBOX.h;
  return [Math.round(x * 10) / 10, Math.round(y * 10) / 10];
}

